class Solution {
public:
    string countOfAtoms(string formula) {
        unordered_map<string, int> atomCount;
        stack<unordered_map<string, int>> st;
        st.push(atomCount);
        int i = 0;
        while (i < formula.size()) {
            if (formula[i] == '(') {
                st.push(atomCount);
                atomCount.clear();
                i++;
            } else if (formula[i] == ')') {
                unordered_map<string, int> prev = st.top();
                st.pop();
                for (auto& [atom, count] : atomCount) {
                    prev[atom] += count;
                }
                atomCount = prev;
                i++;
            } else if (isalpha(formula[i])) {
                string atom = "";
                while (isalnum(formula[i])) {
                    atom += formula[i++];
                }
                if (i < formula.size() && isdigit(formula[i])) {
                    int count = 0;
                    while (isdigit(formula[i])) {
                        count = count * 10 + formula[i++] - '0';
                    }
                    atomCount[atom] += count;
                } else {
                    atomCount[atom]++;
                }
            }
        }
        string result;
        for (auto& [atom, count] : atomCount) {
            result += atom;
            if (count > 1) {
                result += to_string(count);
            }
        }
        sort(result.begin(), result.end());
        return result;
    }
};
